INSERT INTO public.master_qa (trimester, topic, question_bn, answer_bn, severity) VALUES
('POSTPARTUM', 'প্রসব_পরবর্তী_যত্ন', 'প্রসবের পর এখনও কিছু রক্ত যাচ্ছে। এটা কি স্বাভাবিক?', 'আপা, প্রসবের পর কয়েক সপ্তাহ পর্যন্ত কিছু রক্তপাত হওয়া স্বাভাবিক। তবে এক ঘণ্টায় একাধিক প্যাড ভিজলে, বড় বড় রক্তের দলা বের হলে বা মাথা ঘুরলে দ্রুত হাসপাতালে যান।', 'HIGH'),
('POSTPARTUM', 'প্রসব_পরবর্তী_যত্ন', 'শিশুর জন্য রাতে ঘুমাতে পারছি না।', 'আপা, নবজাতকের যত্ন নিতে গিয়ে অনেক মায়ের ঘুম কম হয়। শিশু ঘুমালে আপনিও বিশ্রাম নিন, পরিবারের সদস্যদের সাহায্য নিন এবং নিজের খাওয়া-দাওয়া ঠিক রাখুন। আপনার সুস্থতাও খুব গুরুত্বপূর্ণ।', 'LOW'),
('POSTPARTUM', 'প্রসব_পরবর্তী_যত্ন', 'আজ আমার জ্বর এসেছে।', 'আপা, প্রসবের পর জ্বর হলে তা সংক্রমণের লক্ষণ হতে পারে। সেলাইয়ের জায়গায় ব্যথা বাড়লে, দুর্গন্ধযুক্ত স্রাব হলে বা শরীর কাঁপলে দ্রুত স্বাস্থ্যকর্মী বা চিকিৎসকের সাথে যোগাযোগ করুন।', 'MODERATE'),
('POSTPARTUM', 'প্রসব_পরবর্তী_যত্ন', 'উঠলেই মাথা ঘোরে।', 'আপা, প্রসবের পর রক্তস্বল্পতা বা দুর্বলতার কারণে এমন হতে পারে। প্রোটিনসমৃদ্ধ খাবার, শাকসবজি, ডিম ও আয়রন ট্যাবলেট গ্রহণ করুন। লক্ষণ বেশি হলে অবশ্যই পরীক্ষা করান।', 'MODERATE'),
('POSTPARTUM', 'প্রসব_পরবর্তী_যত্ন', 'প্রসবের পরে ব্যায়াম কখন থেকে করতে পারব?', 'আপা, সাধারণত স্বাভাবিক প্রসবের পরে হালকা হাঁটা কয়েক দিনের মধ্যেই শুরু করা যায়। ভারী ব্যায়াম শুরু করবেন না এবং সিজারিয়ান হলে চিকিৎসকের অনুমতি নিন। ধীরে ধীরে স্বাভাবিক কার্যক্রমে ফিরে আসুন।', 'LOW'),
('POSTPARTUM', 'বুকের_দুধ', 'দুধ খেতে খেতে আমার শিশু ঘুমিয়ে যায়।', 'আপা, নবজাতক শিশুদের অনেক সময় দুধ খেতে খেতে ঘুমিয়ে পড়া স্বাভাবিক। শিশু অন্তত ১০–১৫ মিনিট দুধ খায় তা নিশ্চিত করুন, এক পাশ শেষ করে অন্য পাশ দিন এবং গালে আলতো স্পর্শ করে জাগিয়ে রাখুন। খুব দুর্বল লাগলে স্বাস্থ্যকর্মীকে জানান।', 'LOW'),
('POSTPARTUM', 'বুকের_দুধ', 'আমার বুকের দুধের রং একটু হলুদ। এটা কি সমস্যা?', 'না আপা, এটি একদম স্বাভাবিক। প্রসবের পর প্রথম কয়েকদিন যে হলুদাভ দুধ আসে তাকে শালদুধ (Colostrum) বলা হয়। এটি রোগ প্রতিরোধ ক্ষমতা বাড়ায় ও রোগ থেকে সুরক্ষা দেয়, তাই এই দুধ অবশ্যই শিশুকে খাওয়াবেন।', 'LOW'),
('POSTPARTUM', 'বুকের_দুধ', 'গরমে কি শিশুকে আলাদা করে পানি দিতে হবে?', 'না আপা। ছয় মাস বয়স পর্যন্ত শিশুর জন্য শুধু বুকের দুধই যথেষ্ট। বুকের দুধেই পর্যাপ্ত পানি, পুষ্টি ও রোগ প্রতিরোধ ক্ষমতা থাকে। ছয় মাস পর্যন্ত পানি বা অন্য খাবার দেওয়ার প্রয়োজন নেই।', 'LOW'),
('POSTPARTUM', 'বুকের_দুধ', 'ঘরের কাজ করতে হয়। দুধ খাওয়ানোর সময় পাচ্ছি না।', 'আপা, ঘরের কাজের পাশাপাশি শিশুর যত্ন নেওয়া কঠিন হতে পারে। তবে কাজের ফাঁকে ফাঁকে শিশুকে বুক দিন, পরিবারের সাহায্য নিন এবং দীর্ঘ সময় শিশুকে না খাইয়ে রাখবেন না। বুকের দুধই এখন শিশুর সবচেয়ে গুরুত্বপূর্ণ খাবার।', 'LOW'),
('POSTPARTUM', 'বুকের_দুধ', 'দুধ খাওয়ার পরে শিশুর হেঁচকি উঠছে।', 'আপা, দুধ খাওয়ার পরে অনেক শিশুরই হেঁচকি ওঠে এবং এটি সাধারণত ক্ষতিকর নয়। দুধ খাওয়ানোর পর শিশুকে কাঁধে নিয়ে ঢেকুর তুলান, খুব দ্রুত খাওয়ানো এড়ান এবং সোজা অবস্থায় রাখুন। শ্বাসকষ্ট হলে স্বাস্থ্যকর্মীকে জানান।', 'LOW');
